#include <bits/stdc++.h>
using namespace std;

const int N=1e5+5;

struct Node{
    int l,r;
}f[N];

bool cmp(Node x,Node y){
    if(x.l==y.l)
        return x.r>y.r;
    return x.l<y.l;
}

int n,a[N],b[N],ml,mr=1e9,ans;

int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++){
        scanf("%d%d",&a[i],&b[i]);
        ml=max(ml,a[i]),mr=min(mr,b[i]);
    }
    for(int i=1;i<=n;i++){
        ans=max(ans,b[i]-a[i]+1+max(mr-ml+1,0));
        f[i]={max(b[i]-ml+1,0),max(mr-a[i]+1,0)};
    }
    sort(f+1,f+n+1,cmp);
    int num=1e9;
    for(int i=1;i<n;i++){
        num=min(num,f[i].r);
        ans=max(ans,f[i+1].l+num);
    }
    printf("%d",ans);
    return 0;
}
